12→public class SpacingAroundRangeOperatorRule : StandardRule("range-spacing") {
13→    override fun beforeVisitChildNodes(
14→        node: ASTNode,
15→        autoCorrect: Boolean,
16→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
17→    ) {
18→        if (node.elementType == RANGE || node.elementType == RANGE_UNTIL) {
19→            val prevLeaf = node.prevLeaf()
20→            val nextLeaf = node.nextLeaf()
21→            when {
22→                prevLeaf is PsiWhiteSpace && nextLeaf is PsiWhiteSpace -> {
23→                    emit(node.startOffset, "Unexpected spacing around \"${node.text}\"", true)
24→                    if (autoCorrect) {
25→                        prevLeaf.node.treeParent.removeChild(prevLeaf.node)
26→                        nextLeaf.node.treeParent.removeChild(nextLeaf.node)
27→                    }
28→                }
29→                prevLeaf is PsiWhiteSpace -> {
30→                    emit(prevLeaf.node.startOffset, "Unexpected spacing before \"${node.text}\"", true)
31→                    if (autoCorrect) {
32→                        prevLeaf.node.treeParent.removeChild(prevLeaf.node)
33→                    }
34→                }
35→                nextLeaf is PsiWhiteSpace -> {
36→                    emit(nextLeaf.node.startOffset, "Unexpected spacing after \"${node.text}\"", true)
37→                    if (autoCorrect) {
38→                        nextLeaf.node.treeParent.removeChild(nextLeaf.node)
39→                    }
40→                }
41→            }
42→        }
43→    }
44→}
45→
46→public val SPACING_AROUND_RANGE_OPERATOR_RULE_ID: RuleId = SpacingAroundRangeOperatorRule().ruleId
